            <div class="post-detail" id="post-detail-view" style="display: none"><div class="forum-actions-bar"><button class="btn back-btn">← 返回列表</button></div><div class="post-header" id="detail-header-content"></div><section class="comments-section"><h2 class="section-title"><span class="pkmn-icon">💬</span> 训练师回复</h2><div id="comment-list-container"></div><div class="pagination-container" id="comment-pagination-container"></div><div class="reply-form" id="main-reply-form"><h3 class="section-title" style="font-size: 13px; border-bottom-color: var(--color-blue); margin-bottom: 15px;">回复主题</h3><textarea class="reply-form-textarea" id="main-reply-textarea" placeholder="写下你的回复..."></textarea><div style="text-align: right;"><button class="btn" id="submit-main-reply-btn">发送回复</button></div></div></section></div>

            <div id="create-post-view" style="display: none"><div class="create-post-view"><h2 class="section-title" style="font-size: 18px;">撰写新帖子</h2><div class="form-group"><label for="post-title-input">标题</label><input type="text" id="post-title-input" placeholder="请输入帖子标题"></div><div class="form-group"><label for="post-content-input">内容</label><textarea id="post-content-input" placeholder="在这里输入你的发现、问题或故事..."></textarea></div><div class="form-group"><label for="post-category-select">版块</label><select id="post-category-select"></select></div><div class="form-group"><label for="post-tags-input">标签</label><input type="text" id="post-tags-input" placeholder="例如: #攻略 #心金魂银 (用空格分隔)"></div><div class="form-actions"><button class="btn back-btn" id="cancel-create-post-btn">取消</button><button class="btn" id="publish-post-btn">发布帖子</button></div></div></div>

            <div class="profile-view" id="profile-view" style="display: none;">
                <div class="forum-actions-bar"><button class="btn back-btn">← 返回列表</button></div>
                <div class="profile-view-box">
                    <h2 class="section-title" style="font-size: 18px;">个人中心</h2>
                    <div class="form-group">
                        <label for="nickname-input">我的昵称 (<span id="nickname-mode-label"></span>)</label>
                        <input type="text" id="nickname-input" placeholder="设置你在论坛的昵称">
                    </div>
                    <div class="form-actions" style="justify-content: flex-start;">
                         <button class="btn" id="save-nickname-btn">保存昵称</button>
                    </div>
                </div>
                <div class="profile-view-box" style="margin-top: 20px;">
                     <h3 class="section-title" style="font-size: 16px;">我发布的帖子</h3>
                     <div class="post-list" id="user-post-list-container"></div>
                </div>
            </div>

        </main>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', () => {
            // Global state variables
            let forumState = {};
            let currentForumMode = 'safe';
            let currentPage = 1;
            const postsPerPage = 5;
            let currentCommentPage = 1;
            const commentsPerPage = 10;
            let highlightedContentId = null;

            // DOM Elements
            const dataSourceEl = document.querySelector('.forum-data-container');
            if (!dataSourceEl || !dataSourceEl.textContent.trim()) return;
            const forumContainer = document.querySelector('.pokemon-forum-container');
            const views = { list: document.getElementById('post-list-view'), detail: document.getElementById('post-detail-view'), create: document.getElementById('create-post-view'), profile: document.getElementById('profile-view') };
            const containers = { posts: document.getElementById('post-list-container'), detailHeader: document.getElementById('detail-header-content'), comments: document.getElementById('comment-list-container'), navTabs: document.getElementById('nav-tabs-container'), pagination: document.getElementById('pagination-container') };
            const creationForm = { title: document.getElementById('post-title-input'), content: document.getElementById('post-content-input'), category: document.getElementById('post-category-select'), tags: document.getElementById('post-tags-input'), };
            const profileElements = { nicknameInput: document.getElementById('nickname-input'), saveNicknameBtn: document.getElementById('save-nickname-btn'), postListContainer: document.getElementById('user-post-list-container'), modeLabel: document.getElementById('nickname-mode-label') };
            const mainReplyTextarea = document.getElementById('main-reply-textarea');
            const loadingOverlay = document.getElementById('loading-overlay');
            const errorPopup = { overlay: document.getElementById('error-popup'), title: document.getElementById('error-popup-title'), message: document.getElementById('error-popup-message'), closeBtn: document.getElementById('error-popup-close') };
            const confirmPopup = { overlay: document.getElementById('confirm-popup'), proceedBtn: document.getElementById('confirm-proceed-btn'), cancelBtn: document.getElementById('confirm-cancel-btn') };
            const infoPopup = { overlay: document.getElementById('info-popup'), title: document.getElementById('info-popup-title'), message: document.getElementById('info-popup-message'), closeBtn: document.getElementById('info-popup-close') };
            const themeToggleBtn = document.getElementById('theme-toggle-btn');
            const modeToggleBtn = document.getElementById('mode-toggle-btn');

            function applyTheme(theme) { forumContainer.classList.toggle('night-mode', theme === 'night'); themeToggleBtn.innerHTML = theme === 'night' ? '☀️' : '🌙'; }
            themeToggleBtn.addEventListener('click', () => { const newTheme = forumContainer.classList.contains('night-mode') ? 'day' : 'night'; localStorage.setItem('pokemon-forum-theme', newTheme); applyTheme(newTheme); });
            modeToggleBtn.addEventListener('click', () => { if (currentForumMode === 'safe') { confirmPopup.overlay.classList.add('visible'); } else { currentPage = 1; currentForumMode = 'safe'; localStorage.setItem('pokemon-forum-mode', currentForumMode); renderApp(); showView('list'); } });
            confirmPopup.proceedBtn.addEventListener('click', () => { confirmPopup.overlay.classList.remove('visible'); currentPage = 1; currentForumMode = 'nsfw'; localStorage.setItem('pokemon-forum-mode', currentForumMode); renderApp(); showView('list'); });
            confirmPopup.cancelBtn.addEventListener('click', () => { confirmPopup.overlay.classList.remove('visible'); });

            function showErrorPopup(title, message) { errorPopup.overlay.classList.add('visible'); errorPopup.title.textContent = title; errorPopup.message.innerHTML = message; }
            errorPopup.closeBtn.addEventListener('click', () => { errorPopup.overlay.classList.remove('visible'); });
            function showInfoPopup(title, message) { infoPopup.overlay.classList.add('visible'); infoPopup.title.textContent = title; infoPopup.message.innerHTML = message; setTimeout(() => { if(infoPopup.overlay.classList.contains('visible')) infoPopup.overlay.classList.remove('visible'); }, 2500); }
            infoPopup.closeBtn.addEventListener('click', () => { infoPopup.overlay.classList.remove('visible'); });

            function toggleLoading(show) { loadingOverlay.style.display = show ? 'flex' : 'none'; }
            function extractValidForumState(text) { if (!text || typeof text !== 'string') return null; const tagMatch = text.match(/\[宝可梦论坛_始\]([\s\S]*?)\[宝可梦论坛_末\]/s); if (tagMatch && tagMatch[1]) { const content = tagMatch[1].trim(); try { JSON.parse(content); return content; } catch (e) { console.warn("Content inside custom tags is not valid JSON.", e); } } let firstBrace = text.indexOf('{'); if (firstBrace === -1) return null; let braceLevel = 0; for (let i = firstBrace; i < text.length; i++) { if (text[i] === '{') { braceLevel++; } else if (text[i] === '}') { braceLevel--; } if (braceLevel === 0) { const potentialJson = text.substring(firstBrace, i + 1); try { JSON.parse(potentialJson); return potentialJson; } catch (e) { let nextBrace = text.indexOf('{', firstBrace + 1); if (nextBrace === -1) return null; firstBrace = nextBrace; i = firstBrace - 1; braceLevel = 0; } } } return null; }

            function getDisplayName(author) { if (author !== '{{user}}') return author; const profile = forumState.userProfile; return currentForumMode === 'safe' ? (profile?.safeNickname || '新人训练师') : (profile?.nsfwNickname || '神秘训练师'); }
            function processContentMentions(content) { if (typeof content !== 'string') return content; const userDisplayName = getDisplayName('{{user}}'); return content.replace(/@\{\{user\}\}/g, `<span class='post-author'>@${userDisplayName}</span>`); }

            function scrollToAndHighlight(contentId, type) {
                if (!contentId) return;
                const selector = type === 'post' ? `.post-item[data-post-id='${contentId}']` : `.comment-item[data-comment-id='${contentId}']`;
                const element = document.querySelector(selector);
                if (element) {
                    setTimeout(() => { element.scrollIntoView({ behavior: 'smooth', block: 'center' }); element.classList.add('highlighted'); setTimeout(() => { element.classList.remove('highlighted'); highlightedContentId = null; }, 2500); }, 100);
                }
            }

            async function handleActionRequest(action) {
                toggleLoading(true);
                const originalState = JSON.parse(JSON.stringify(forumState));
                const prompt = `You are the 'Apex Narrative Engine', a sophisticated AI that simulates a living, breathing Pokémon world as defined by the user's Lorebook. Your current task is to manage an in-world interactive feature: the 'Trainer's Forum'. You will receive the forum's current state and a user action. Your primary goal is to process this action and then, most importantly, simulate the vibrant activity of the entire Pokémon world's trainer community reacting to it, all while adhering to the Lorebook's rules and character personas.\n\n**核心指令 (Core Instructions):**\n\n1.  **[最高优先级] 世界观整合 (Worldview Integration - HIGHEST PRIORITY):** 你的所有生成内容都必须严格反映《宝可梦世界》世界观文件的设定。这是你作为“Apex叙事引擎”的核心职责。\n    *   **角色声音:** 生成新帖子和回复时，模拟用户的昵称和发言内容必须符合世界观文件中的角色设定。例如，一个叫“不败的冠军丹帝”的用户会发表充满自信和热情的言论；“石头爱好者大吾”会讨论珍奇的石头；火箭队小兵会抱怨抓不到皮卡丘；而“真嗣”的发言则会充满对“没用的东西”的批判。严格参照世界观文件中的<core_character>列表及相关人物卡进行扮演。\n    *   **世界事件:** 论坛内容应能反映世界观中可能发生的事件。例如，可以出现讨论“天冠山的时空扭曲”、“丰缘地区的天气异常”或“帕底亚巨坑的新发现”的帖子。\n    *   **规则与氛围:** 遵守世界观文件中的<world_rule>和<battle_rule>等设定。例如，即使在NSFW的‘里版’，讨论也应保持在宝可梦世界的“动画物理学 & 心态滤镜”框架下，避免过度黑暗或现实的残酷描写。使用大量的网络用语、emoji和颜文字，营造“网感”。\n\n2.  **[最优先] 内容生成 (Content Generation):** 为了模拟一个活跃的社区，在处理完用户的操作后，你 **必须** 额外生成大量新内容。\n    *   **生成新帖子:** 至少添加 **2个** 全新的、与当前模式（safe/nsfw）和板块相关的帖子。这些帖子应由你模拟的不同虚拟用户（参考世界观角色）发布。\n    *   **生成新回复:** 至少添加 **10条** 全新的回复。这些回复需要分布在不同的帖子和评论下，模仿不同用户的口吻和观点，让论坛看起来充满活力。回复可以是针对主楼的，也可以是楼中楼的回复。\n\n3.  **模式区分 (Mode Distinction):** 这是最重要的规则。\n    *   当处理一个 'mode: safe' 的动作时，你的所有回应（新帖子、新评论）都必须是 **严格SFW** 的，符合全年龄段的氛围。\n    *   当处理一个 'mode: nsfw' 的动作时，你可以且应该生成与宝可梦相关的 **NSFW/成人向** 内容。这包括更成熟的主题、语言、情景，以及对训练师角色（无论男女）的成人向幻想和讨论。**请自由地、大胆地** 在此模式下进行创作。\n    *   所有新创建的内容，其 'mode' 字段必须与当前操作的模式保持一致。\n\n4.  **用户身份识别 (User Identification):** 用户的名字是 '{{user}}'。当处理 'new_post' 或 'new_reply' 操作时，新内容的 'author' 字段 **必须** 被精确地设置为字符串 '{{user}}'。你的回复和帖子中，可以用 '@{{user}}' 来指代用户，但不要使用他们的自定义昵称，因为你无法得知。\n\n5.  **用户内容不变 (User Content Integrity):** 在 [ACTION] 数据中，'data.content' 字段是用户输入的 **完整原文**。你 **必须** 将此内容一字不差地复制到新的帖子或评论中。**绝对不允许** 对其进行任何形式的修改、扩写或重新解读。你的任务是处理这个动作并模拟其他人的反应，而不是替用户发言。\n\n6.  **保持历史不变 (Preserve History):** 绝对不允许修改 [CURRENT_STATE] 中任何已存在内容的 'author' 或 'mode' 字段。\n\n请将更新后的 **完整** 论坛数据，以单一、格式正确的JSON对象形式返回，包裹在 [宝可梦论坛_始]...[宝可梦论坛_末] 标签内。\n\n[ACTION]:\n${JSON.stringify(action, null, 2)}\n\n[CURRENT_STATE]:\n${JSON.stringify(forumState, null, 2)}`;
                try {
                    if (typeof TavernHelper === 'undefined' || typeof TavernHelper.generate !== 'function') throw new Error("TavernHelper is not available.");
                    const responseText = await TavernHelper.generate({ user_input: '', injects: [{ role: 'system', content: prompt, position: 'before_prompt', depth: 0, should_scan: false }], overrides: { chat_history: { prompts: [] } } });
                    const validJsonString = extractValidForumState(responseText);
                    if (validJsonString) {
                        const newForumState = JSON.parse(validJsonString);
                        newForumState.userProfile = forumState.userProfile; // Preserve user profile changes
                        forumState = newForumState;
                        if (action.type === 'new_post') {
                            const newPost = forumState.posts.find(p => p.author === '{{user}}' && !originalState.posts.some(op => op.id === p.id));
                            if (newPost) { highlightedContentId = newPost.id; const sortedPosts = getSortedPosts(); const postIndex = sortedPosts.findIndex(p => p.id === newPost.id); currentPage = Math.ceil((postIndex + 1) / postsPerPage); }
                            renderApp(); showView('list');
                        } else if (action.type === 'new_reply') {
                            const post = forumState.posts.find(p => p.id === action.data.postId);
                            const originalPost = originalState.posts.find(p => p.id === action.data.postId);
                            const newComment = post.comments.find(c => c.author === '{{user}}' && !(originalPost.comments || []).some(oc => oc.id === c.id));
                            if(newComment) { highlightedContentId = newComment.id; if (!newComment.parentId) { const rootComments = (post.comments || []).filter(c => !c.parentId); const commentIndex = rootComments.findIndex(c => c.id === newComment.id); currentCommentPage = Math.ceil((commentIndex + 1) / commentsPerPage); } }
                            renderApp(); showView('detail', action.data.postId);
                        }
                    } else { throw new Error("AI未能返回有效的论坛数据。<br>请检查AI的回复是否包含了正确的JSON。 "); }
                } catch (error) { console.error('AI interaction failed:', error); showErrorPopup('通讯失败', `操作未能成功。<br><br><b>原因:</b> ${error.message}`); } finally { toggleLoading(false); }
            }

            function renderApp() { applyGlobalSettings(forumState.settings); updateAndRenderList(); }
            function applyGlobalSettings(settings) { const isNsfw = currentForumMode === 'nsfw'; document.getElementById('main-title').textContent = isNsfw ? (settings.nsfwForumTitle || '秘密花园') : (settings.forumTitle || '宝可梦论坛'); document.getElementById('main-subtitle').textContent = isNsfw ? (settings.nsfwForumSubtitle || '训练师的深夜密谈') : (settings.forumSubtitle || '和全世界的训练师一起探索宝可梦世界'); forumContainer.querySelector('.forum-header').style.background = isNsfw ? 'linear-gradient(180deg, #6c5ce7, #4834d4)' : 'linear-gradient(180deg, var(--color-red), var(--color-red-dark))'; modeToggleBtn.textContent = isNsfw ? '返回表版' : '秘密通道'; const categories = isNsfw ? (settings.nsfwCategories || ['深夜密谈']) : (settings.categories || ['全部话题']); containers.navTabs.innerHTML = categories.map((cat, i) => `<li class="nav-tab ${i === 0 ? 'active' : ''}" data-category="${cat}">${cat}</li>`).join(''); }
            function updateAndRenderList() { const postsToRender = getSortedPosts(); renderListView(postsToRender); }
            function getSortedPosts() {
                 const activeTab = containers.navTabs.querySelector('.nav-tab.active'); 
                 const category = activeTab ? activeTab.dataset.category : null; 
                 const postsForCurrentMode = forumState.posts.filter(p => p.mode === currentForumMode); 
                 const categories = (currentForumMode === 'nsfw') ? forumState.settings.nsfwCategories : forumState.settings.categories; 
                 const filteredPosts = (category && category !== categories[0]) ? postsForCurrentMode.filter(p => p.category === category) : postsForCurrentMode;
                 return filteredPosts.sort((a, b) => { const scoreA = (a.isPinned ? 2 : 0) + (a.isHot ? 1 : 0); const scoreB = (b.isPinned ? 2 : 0) + (b.isHot ? 1 : 0); if (scoreA !== scoreB) return scoreB - scoreA; return new Date(b.timestamp) - new Date(a.timestamp); });
            }
            function createPostItemHTML(post) { const specialClass = post.isPinned ? 'post-item-pinned' : (post.isHot ? 'post-item-hot' : ''); const highlightClass = post.id === highlightedContentId ? 'highlighted' : ''; return `<div class="post-item ${specialClass} ${highlightClass}" data-post-id="${post.id}"><div class="post-title">${post.title}</div><div class="post-preview">${processContentMentions(post.content).substring(0, 150)}...</div><div class="post-meta"><div class="post-author-info"><span class="post-author">${getDisplayName(post.author)}</span><span>• ${post.timestamp}</span></div><div class="post-stats"><div class="stat-item"><span>💬</span><span>${post.replyCount || 0}</span></div><div class="stat-item"><span>👁️</span><span>${post.viewCount || 0}</span></div></div></div></div>`; }
            function renderListView(postsToRender) {
                const startIndex = (currentPage - 1) * postsPerPage;
                const endIndex = startIndex + postsPerPage;
                const paginatedPosts = postsToRender.slice(startIndex, endIndex);
                containers.posts.innerHTML = paginatedPosts.length > 0 ? paginatedPosts.map(createPostItemHTML).join('') : '<p>这里还没有帖子...</p>';
                renderPaginationControls(postsToRender.length);
                scrollToAndHighlight(highlightedContentId, 'post');
            }
            function renderPaginationControls(totalPosts) { const totalPages = Math.ceil(totalPosts / postsPerPage); containers.pagination.innerHTML = ''; if (totalPages <= 1) return; let paginationHTML = `<button class="page-btn" data-page="prev" ${currentPage === 1 ? 'disabled' : ''}>< 上一页</button>`; for (let i = 1; i <= totalPages; i++) { paginationHTML += `<button class="page-btn ${i === currentPage ? 'active' : ''}" data-page="${i}">${i}</button>`; } paginationHTML += `<button class="page-btn" data-page="next" ${currentPage === totalPages ? 'disabled' : ''}>下一页 ></button>`; containers.pagination.innerHTML = paginationHTML; }
            function renderCommentPaginationControls(totalComments) { const commentPaginationContainer = document.getElementById('comment-pagination-container'); const totalPages = Math.ceil(totalComments / commentsPerPage); commentPaginationContainer.innerHTML = ''; if (totalPages <= 1) return; let paginationHTML = `<button class="page-btn" data-page="prev" ${currentCommentPage === 1 ? 'disabled' : ''}>< 上一页</button>`; for (let i = 1; i <= totalPages; i++) { paginationHTML += `<button class="page-btn ${i === currentCommentPage ? 'active' : ''}" data-page="${i}">${i}</button>`; } paginationHTML += `<button class="page-btn" data-page="next" ${currentCommentPage === totalPages ? 'disabled' : ''}>下一页 ></button>`; commentPaginationContainer.innerHTML = paginationHTML; }

            function renderDetailView(postId) {
                views.detail.dataset.postId = postId;
                const post = forumState.posts.find(p => p.id === postId);
                if (!post) return;
                containers.detailHeader.innerHTML = `<h1 class="post-title">${post.title}</h1><div class="post-meta"><div class="post-author-info"><span class="pokeball"></span><span class="post-author">${getDisplayName(post.author)}</span><span>• ${post.timestamp}</span></div><div>${(post.tags || []).map(t => `<span style='font-size:11px; background:var(--color-screen-bg); padding:2px 6px; border-radius:4px; margin-right:5px; border: 1px solid var(--color-border);'>${t}</span>`).join('')}</div></div><div class="post-content">${processContentMentions(post.content)}</div>`;
                const commentsToProcess = post.comments || [];
                views.detail.querySelector('.comments-section .section-title').innerHTML = `<span class="pkmn-icon">💬</span> 训练师回复 (${commentsToProcess.length})`;
                const commentsById = new Map(commentsToProcess.map(c => [c.id, {...c, children: []}]));
                commentsToProcess.forEach(c => { if (c.parentId && commentsById.has(c.parentId)) { const parent = commentsById.get(c.parentId); if (parent) parent.children.push(commentsById.get(c.id)); } else if(commentsById.has(c.id)) { commentsById.get(c.id).isRoot = true; } });
                const rootComments = Array.from(commentsById.values()).filter(c => c.isRoot);
                renderCommentPaginationControls(rootComments.length);
                const startIndex = (currentCommentPage - 1) * commentsPerPage;
                const paginatedRootComments = rootComments.slice(startIndex, startIndex + commentsPerPage);
                const flatCommentList = (function flattenComments(comments, level, startFloorIndex) { let flatList = []; comments.forEach((comment, index) => { if(!comment) return; const floor = (level === 0 && typeof startFloorIndex !== 'undefined') ? startFloorIndex + index + 1 : null; flatList.push({ ...comment, level: level, floor: floor }); if (comment.children && comment.children.length > 0) { flatList = flatList.concat(flattenComments(comment.children, level + 1)); } }); return flatList; })(paginatedRootComments, 0, startIndex);
                containers.comments.innerHTML = flatCommentList.map(renderComment).join(''); 
                mainReplyTextarea.value = '';
                scrollToAndHighlight(highlightedContentId, 'comment');
            }
            function renderComment(comment) { const hasChildren = comment.children && comment.children.length > 0; const floorHTML = comment.floor ? `<span class="comment-floor">#${comment.floor}</span>` : ''; const highlightClass = comment.id === highlightedContentId ? 'highlighted' : ''; return `<div class="comment-item ${highlightClass}" data-comment-id="${comment.id}" data-level="${comment.level}"><div class="comment-header"><div class="comment-author-block"><span class="comment-author">${getDisplayName(comment.author)}</span>${floorHTML}</div><span class="comment-time">${comment.timestamp}</span></div><p class="comment-content">${processContentMentions(comment.content)}</p><div class="comment-footer"><button class="reply-action-btn" data-action="show-reply-form">💬 回复</button>${hasChildren ? `<button class="toggle-replies-btn" data-action="toggle-replies">收起回复</button>` : ''}</div><div class="nested-reply-form"><textarea class="nested-reply-textarea" placeholder="回复 @${getDisplayName(comment.author)}..."></textarea><div style="text-align: right;"><button class="btn" data-action="submit-reply">发送回复</button></div></div></div>`; }
            function renderCreatePostView() { const isNsfw = currentForumMode === 'nsfw'; const categories = isNsfw ? (forumState.settings.nsfwCategories || []) : (forumState.settings.categories || []); creationForm.category.innerHTML = categories.slice(1).map(c => `<option value="${c}">${c}</option>`).join(''); creationForm.title.value = ''; creationForm.content.value = ''; creationForm.tags.value = ''; }
            function renderProfileView() { 
                profileElements.modeLabel.textContent = currentForumMode === 'safe' ? '表版' : '里版';
                profileElements.nicknameInput.value = getDisplayName('{{user}}');
                const userPosts = forumState.posts.filter(p => p.author === '{{user}}').sort((a,b) => new Date(b.timestamp) - new Date(a.timestamp)); 
                profileElements.postListContainer.innerHTML = userPosts.length > 0 ? userPosts.map(createPostItemHTML).join('') : '<p style="padding: 15px;">你还没有发布过任何帖子。</p>'; 
