    function getDangerStage(value) {
      if (value <= 20) return '收敛 - 偷偷瞄、保持距离';
      if (value <= 40) return '试探 - 盯着看、找借口靠近、碰手';
      if (value <= 70) return '明显 - 直勾勾盯、主动贴上来、直接上手摸';
      return '动手 - 直接动手、按住不让动、撕衣服';
    }

    function calculateEndings() {
      const data = getAllVariables();
      const npcList = _.get(data, 'stat_data.在场NPC', {});

      let totalDanger = 0;
      let npcCount = 0;

      Object.values(npcList).forEach(npc => {
        if (npc !== '待初始化' && typeof npc === 'object') {
          totalDanger += (npc.侵犯值 || 0);
          npcCount++;
        }
      });

      const avgDanger = npcCount > 0 ? totalDanger / npcCount : 0;

      let probabilities = {
        escape: Math.max(5, 70 - avgDanger * 0.7),
        submit: Math.min(40, avgDanger * 0.4),
        toy: Math.min(35, avgDanger * 0.35),
        exclusive: npcCount === 1 ? Math.min(30, avgDanger * 0.3) : 0,
        famous: npcCount >= 3 ? Math.min(40, avgDanger * 0.4) : 0
      };

      const total = Object.values(probabilities).reduce((a, b) => a + b, 0);
      if (total > 0) {
        Object.keys(probabilities).forEach(key => {
          probabilities[key] = Math.round((probabilities[key] / total) * 100);
        });
      }

      return probabilities;
    }

    function updateEndingPreview() {
      const probs = calculateEndings();
      const container = $('#ending-preview');
      container.empty();

      endingTypes.forEach(ending => {
        const percent = probs[ending.key] || 0;
        container.append(`
          <div class="ending-item">
            <span class="ending-name" title="${ending.desc}">${ending.name}</span>
            <div class="ending-bar">
              <div class="ending-fill" style="width: ${percent}%"></div>
            </div>
            <span class="ending-percent">${percent}%</span>
          </div>
        `);
      });
    }

    function updateHistory(result, description, prompt) {
      const time = new Date().toLocaleTimeString('zh-CN', {hour:'2-digit',minute:'2-digit'});
      const record = { time, result, description, prompt };
      rollHistory.unshift(record);
      if (rollHistory.length > 10) rollHistory.pop();

      const container = $('#roll-history');
      container.empty();
      rollHistory.forEach((rec, idx) => {
        container.append(`<div class="history-item" data-index="${idx}">[${rec.time}] ${rec.result}点 - ${rec.description}</div>`);
      });
    }

    function rollDice() {
      const result = Math.floor(Math.random() * 6) + 1;
      $('#dice-value').text(result).addClass('rolling');

      setTimeout(() => {
        $('#dice-value').removeClass('rolling');

        let prompt = '';
        let description = '';

        if (diceMode === 'scene') {
          const sceneList = sceneEvents[result];
          const scene = sceneList[Math.floor(Math.random() * sceneList.length)];
          const assaultList = assaultActions[result];
          const assault = assaultList[Math.floor(Math.random() * assaultList.length)];

          $('#result-content').html(`
            <div class="scene-card">
              <div class="scene-header">
                <div class="scene-badge">${scene.name}</div>
                <div class="scene-type">强度 ${result}/6</div>
              </div>
              <div class="scene-desc">${scene.desc}</div>
              <div class="scene-detail">${scene.detail}</div>
            </div>
            <div class="assault-card">
              <div class="assault-level">
                ${Array(result).fill('<i class="fas fa-fire danger-icon"></i>').join('')}
                <span style="margin-left:4px;font-size:10px;color:var(--text-dim);">侵犯度${result}/6</span>
              </div>
              <div class="assault-text">${assault}</div>
            </div>
          `);

          prompt = `[场景触发]\n\n${scene.name}：\n${scene.desc}\n\n细节：${scene.detail}\n\n接下来：${assault}`;
          description = `${scene.name} + 侵犯行为`;

        } else if (diceMode === 'assault') {
          const assaultList = assaultActions[result];
          const assault = assaultList[Math.floor(Math.random() * assaultList.length)];

          $('#result-content').html(`
            <div class="assault-card">
              <div class="assault-level">
                ${Array(result).fill('<i class="fas fa-fire danger-icon"></i>').join('')}
                <span style="margin-left:4px;font-size:10px;color:var(--text-dim);">侵犯度${result}/6</span>
              </div>
              <div class="assault-text">${assault}</div>
            </div>
          `);

          if (currentNpc) {
            prompt = `${currentNpc}${assault}`;
          } else {
            prompt = `[侵犯行为] ${assault}`;
          }
          description = assault.substring(0, 20) + '...';

        } else if (diceMode === 'luck') {
          const luckList = luckEvents[result];
          const luck = luckList[Math.floor(Math.random() * luckList.length)];

          $('#result-content').html(`
            <div class="scene-card">
              <div class="scene-header">
                <div class="scene-badge">运势判定</div>
                <div class="scene-type">${result}点</div>
              </div>
              <div class="scene-desc" style="font-size:12px;">${luck}</div>
            </div>
          `);

          prompt = `[运势] ${luck}`;
          description = luck;
        }

        updateHistory(result, description, prompt);
        copyToDialog(prompt);
        showToast('已填入对话框', 'success');
      }, 500);
    }

