    function savePlans() {
      try {
        if (typeof localStorage !== 'undefined') {
          localStorage.setItem('xuexiang_plans', JSON.stringify(plotPlans));
        }
      } catch (e) {}
    }

    function loadPlans() {
      try {
        if (typeof localStorage !== 'undefined') {
          const saved = localStorage.getItem('xuexiang_plans');
          if (saved) {
            plotPlans = JSON.parse(saved);
          }
        }
      } catch (e) {}
    }

    function renderPlans() {
      const container = $('#plan-list');
      container.empty();

      if (plotPlans.length === 0) {
        container.html('<div class="empty"><i class="fas fa-clipboard-list"></i><p>暂无计划</p></div>');
        return;
      }

      plotPlans.forEach((plan, index) => {
        container.append(`
          <div class="plan-item">
            <button class="delete-btn" data-index="${index}">
              <i class="fas fa-times"></i>
            </button>
            <div class="plan-type">[${plan.type}]</div>
            <div class="plan-content">${plan.content}</div>
          </div>
        `);
      });
    }

    function addPlan(type, content) {
      plotPlans.push({ type, content });
      savePlans();
      renderPlans();
    }

    function deletePlan(index) {
      plotPlans.splice(index, 1);
      savePlans();
      renderPlans();
    }

    function clearAllPlans() {
      if (confirm('确定清空所有计划吗?')) {
        plotPlans = [];
        savePlans();
        renderPlans();
        showToast('已清空所有计划', 'success');
      }
    }

    function executePlans() {
      if (plotPlans.length === 0) {
        showToast('没有计划可执行', 'error');
        return;
      }

      let prompt = '[执行剧情计划]\n\n';
      plotPlans.forEach((plan, idx) => {
        prompt += `${idx + 1}. [${plan.type}] ${plan.content}\n`;
      });
      prompt += '\n请按照以上计划推进剧情,适当增加侵犯值。';

      copyToDialog(prompt);
      showToast(`已执行${plotPlans.length}个计划`, 'success');
    }

